// Stripe signature verification happens via n8n's webhook middleware
// This node validates the event type and extracts the payload

const event = $input.first().json;

// Extract the Stripe event object
const stripeEvent = event.body || {};
const eventType = stripeEvent.type || '';

// Only process completed checkouts and subscription events
const allowedTypes = [
  'checkout.session.completed',
  'checkout.session.async_payment_succeeded',
  'customer.subscription.created',
  'customer.subscription.updated',
  'customer.subscription.deleted',
  'invoice.payment_succeeded',
  'invoice.payment_failed'
];

if (!allowedTypes.includes(eventType)) {
  return { skip: true, event_type: eventType, reason: 'Unhandled event type' };
}

const session = stripeEvent.data?.object || {};

return {
  skip: false,
  event_type: eventType,
  session_id: session.id,
  customer_email: session.customer_details?.email || session.customer_email || '',
  customer_name: session.customer_details?.name || '',
  amount_total_cents: session.amount_total || 0,
  currency: session.currency || 'usd',
  payment_status: session.payment_status || '',
  stripe_customer_id: session.customer || '',
  stripe_subscription_id: session.subscription || '',
  metadata: session.metadata || {},
  mode: session.mode || 'payment'  // 'payment' or 'subscription'
};

